@import url("https://fonts.googleapis.com/css2?family=Instrument+Serif&family=Azeret+Mono:wght@400;700&display=swap");

:root {
  color: #1a1a1a;
  background: #f0ece4;
  font-family: "Azeret Mono", monospace;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  opacity: 0.04;
  background-image:
    linear-gradient(rgba(26, 26, 26, 0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(26, 26, 26, 0.02) 1px, transparent 1px);
  background-size: 18px 18px;
}

#root {
  min-height: 100vh;
}

.hero-shell {
  min-height: 100vh;
  padding: 32px;
}

.hero-header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 24px;
  border-bottom: 3px solid #1a1a1a;
  padding-bottom: 20px;
}

.eyebrow,
.section-label {
  margin: 0 0 12px;
  font-size: 11px;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: #8d857b;
}

h1,
h2 {
  margin: 0;
  font-family: "Instrument Serif", serif;
  font-weight: 400;
}

h1 {
  font-size: clamp(3rem, 6vw, 4.6rem);
}

h2 {
  font-size: clamp(2rem, 4vw, 3.1rem);
  line-height: 0.96;
}

.live-pill {
  border: 2px solid #e63312;
  color: #e63312;
  padding: 8px 14px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.14em;
}

.hero-grid {
  display: grid;
  grid-template-columns: minmax(0, 1.5fr) minmax(280px, 0.8fr);
  gap: 24px;
  padding-top: 28px;
}

.hero-copy,
.hero-panel {
  border: 2px solid #1a1a1a;
  background: rgba(247, 243, 236, 0.9);
  padding: 24px;
}

.hero-copy p:last-child {
  margin-bottom: 0;
  max-width: 60ch;
  line-height: 1.7;
}

.hero-panel ol {
  margin: 0;
  padding-left: 20px;
  display: grid;
  gap: 14px;
  line-height: 1.6;
}

@media (max-width: 800px) {
  .hero-shell {
    padding: 20px;
  }

  .hero-header {
    align-items: flex-start;
    flex-direction: column;
  }

  .hero-grid {
    grid-template-columns: 1fr;
  }
}

